class Solution {
public:
    int maxSubstrings(string word) {
        int n = word.length();
        if (n < 4) return 0;

        int count = 0;
        unordered_set<char> used;
        for (int i = 0; i < n - 3; ++i) {
            if (used.find(word[i]) != used.end()) continue;
            for (int j = i + 3; j < n; ++j) {
                if (word[j] == word[i]) {
                    ++count;
                    used.insert(word[i]);
                    i = j; // Move i to j to avoid overlapping
                    break;
                }
            }
        }
        return count;
    }
};

